import jwt
from jwt import exceptions

class JWTWrapper(object):
    def __init__(self, algorithms=['HS256', 'RS256']):
        self.algorithms = algorithms

    def verify_jwt(self, token, key=None, algorithms=None):
        """Verify a JSON Web Token (JWT) and return the decoded payload."""
        if not algorithms:
            algorithms = self.algorithms
        try:
            decoded_token = jwt.decode(token, key, algorithms=algorithms)
        except exceptions.InvalidTokenError:
            raise ValueError('Invalid token')
        return decoded_token

    def extract_payload(self, token):
        """Extract the payload of a JSON Web Token (JWT)."""
        try:
            decoded_token = self.verify_jwt(token)
        except ValueError as e:
            raise exceptions.InvalidTokenError('Invalid token') from e
        return decoded_token['payload']